interface Chunk { start: number; end: number; }

function findChunkAtOffset(chunks: Chunk[], offset: number): number {
  let left = 0;
  let right = chunks.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    if (offset < chunks[mid].start) right = mid - 1;
    else if (offset >= chunks[mid].end) left = mid + 1;
    else return mid;
  }

  return -1; // offset outside all chunks
}

// findChunkAtOffset([{start:0,end:200},{start:200,end:450},{start:450,end:900}], 350)
// => 1  (offset 350 falls in chunk[1]: 200–450)

interface TimelineEvent { time: number; label: string; }

function findActiveEvent(
  events: TimelineEvent[],
  currentTime: number
): TimelineEvent | null {
  let left = 0;
  let right = events.length - 1;
  let result: TimelineEvent | null = null;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    if (events[mid].time <= currentTime) {
      result = events[mid]; // candidate — keep searching right
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return result;
}

// findActiveEvent([{time:0,label:'Intro'},{time:5.2,label:'Chapter 1'},{time:12.8,label:'Chapter 2'}], 8.5)
// => { time: 5.2, label: 'Chapter 1' }

