function searchRotated(arr: number[], target: number): number {
  let left = 0, right = arr.length - 1;
  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    if (arr[mid] === target) return mid;
    if (arr[left] <= arr[mid]) { // left half sorted
      if (target >= arr[left] && target < arr[mid]) right = mid - 1;
      else left = mid + 1;
    } else { // right half sorted
      if (target > arr[mid] && target <= arr[right]) left = mid + 1;
      else right = mid - 1;
    }
  }
  return -1;
}

function snapToScale(scale: number[], val: number): number {
  let left = 0, right = scale.length;
  while (left < right) {
    const mid = Math.floor((left + right) / 2);
    if (scale[mid] < val) left = mid + 1;
    else right = mid;
  }
  if (left === 0) return scale[0];
  if (left === scale.length) return scale[scale.length - 1];
  const before = scale[left - 1];
  const after = scale[left];
  return (val - before) <= (after - val) ? before : after;
}

async function firstBadBuild(n: number, isBadBuild: (n: number) => Promise<boolean>): Promise<number> {
  let left = 1, right = n;
  while (left < right) {
    const mid = Math.floor((left + right) / 2);
    if (await isBadBuild(mid)) right = mid;
    else left = mid + 1;
  }
  return left;
}
